import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import { useAuth } from '../../context/AuthContext';

export default function CommunityAdminDashboard() {
  const { user } = useAuth();
  const [community, setCommunity] = useState(null);
  const [events, setEvents] = useState([]);
  const [joinRequests, setJoinRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const communityRes = await api.get('/communities/my/profile');
      const c = communityRes.data.data;
      setCommunity(c);

      const [eventsRes, requestsRes] = await Promise.all([
        api.get('/events/my-community'),
        api.get(`/communities/${c._id}/join-requests`),
      ]);
      setEvents(eventsRes.data.data || []);
      setJoinRequests(requestsRes.data.data || []);
    } catch (err) {
      toast.error('Failed to load dashboard');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleJoinRequest = async (communityId, requestId, action, userName) => {
    const endpoint = `/communities/${communityId}/join-requests/${requestId}/${action}`;
    try {
      await api.put(endpoint, action === 'reject' ? { reason: prompt('Reason (optional):') || '' } : {});
      toast.success(`Request ${action}ed for ${userName}`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed');
    }
  };

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* Header */}
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>
                COMMUNITY <span className="gradient-text">DASHBOARD</span>
              </h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>
                {community?.name} — Community Administration
              </p>
            </div>
            <div style={{ display: 'flex', gap: 10 }}>
              <Link to="/community-admin/events" className="btn btn-primary">Manage Events</Link>
              <Link to="/community-admin/members" className="btn btn-outline">View Members</Link>
            </div>
          </div>
        </div>

        {/* Stats */}
        {community && (
          <div className="grid grid-4" style={{ marginBottom: 40 }}>
            {[
              { label: 'Total Members', value: community.members?.length || 0, color: 'var(--purple-light)' },
              { label: 'Pending Requests', value: joinRequests.length, color: 'var(--warning)' },
              { label: 'Total Events', value: events.length, color: 'var(--cyan-accent)' },
              { label: 'Published Events', value: events.filter(e => e.status === 'published').length, color: 'var(--success)' },
            ].map((s, i) => (
              <div key={i} className="stat-card">
                <div className="stat-value" style={{ color: s.color }}>{s.value}</div>
                <div className="stat-label">{s.label}</div>
              </div>
            ))}
          </div>
        )}

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 28 }}>
          {/* Pending Join Requests */}
          <div>
            <div className="flex-between" style={{ marginBottom: 16 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>
                Join Requests
                {joinRequests.length > 0 && (
                  <span style={{ marginLeft: 10, background: 'var(--warning)', color: 'black', borderRadius: 100, padding: '2px 8px', fontSize: '0.7rem' }}>
                    {joinRequests.length}
                  </span>
                )}
              </h3>
              <Link to="/community-admin/members" style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>Manage →</Link>
            </div>

            {joinRequests.length === 0 ? (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-state-icon">✅</div>
                  <div className="empty-state-text">No pending requests</div>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                {joinRequests.slice(0, 5).map(req => (
                  <div key={req._id} className="card" style={{ padding: '14px 18px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 10 }}>
                      <div className="avatar">{req.user?.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{req.user?.name}</div>
                        <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>{req.user?.itNumber}</div>
                      </div>
                    </div>
                    {req.message && (
                      <p style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: 10, fontStyle: 'italic' }}>"{req.message}"</p>
                    )}
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button onClick={() => handleJoinRequest(community._id, req._id, 'approve', req.user?.name)} className="btn btn-success btn-sm" style={{ flex: 1, justifyContent: 'center' }}>✓ Approve</button>
                      <button onClick={() => handleJoinRequest(community._id, req._id, 'reject', req.user?.name)} className="btn btn-danger btn-sm" style={{ flex: 1, justifyContent: 'center' }}>✗ Reject</button>
                    </div>
                  </div>
                ))}
                {joinRequests.length > 5 && (
                  <Link to="/community-admin/members" style={{ textAlign: 'center', fontSize: '0.8rem', color: 'var(--purple-light)', padding: '8px 0' }}>
                    +{joinRequests.length - 5} more →
                  </Link>
                )}
              </div>
            )}
          </div>

          {/* Recent Events */}
          <div>
            <div className="flex-between" style={{ marginBottom: 16 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>Recent Events</h3>
              <Link to="/community-admin/events" style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>All Events →</Link>
            </div>

            {events.length === 0 ? (
              <div className="card">
                <div className="empty-state">
                  <div className="empty-state-icon">📅</div>
                  <div className="empty-state-text">No events yet</div>
                  <Link to="/community-admin/events" className="btn btn-primary btn-sm" style={{ marginTop: 14 }}>Create Event</Link>
                </div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                {events.slice(0, 5).map(ev => (
                  <div key={ev._id} className="card" style={{ padding: '14px 18px' }}>
                    <div className="flex-between">
                      <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{ev.title}</div>
                      <span className={`badge badge-${ev.status}`}>{ev.status}</span>
                    </div>
                    <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: 6, fontFamily: 'var(--font-mono)' }}>
                      📅 {new Date(ev.startDate).toLocaleDateString()} · 👥 {ev.participants?.length || 0} registered
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Community card */}
        {community && (
          <div style={{ marginTop: 40 }}>
            <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', marginBottom: 16 }}>YOUR COMMUNITY</h3>
            <div className="card" style={{ display: 'flex', alignItems: 'center', gap: 20, flexWrap: 'wrap' }}>
              <div className="avatar avatar-xl" style={{ borderRadius: 14, background: 'linear-gradient(135deg, var(--purple-primary), var(--blue-accent))' }}>
                {community.name?.charAt(0)}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 8 }}>
                  <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem' }}>{community.name}</h3>
                  <span className={`badge badge-${community.status}`}>{community.status}</span>
                  <span className={`badge badge-${community.category?.toLowerCase()}`}>{community.category}</span>
                </div>
                <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginBottom: 14 }}>{community.description}</p>
                <div style={{ display: 'flex', gap: 16, fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                  <span>👥 {community.members?.length || 0} Members</span>
                  <span>📅 {events.length} Events</span>
                  <span>📆 Since {new Date(community.createdAt).toLocaleDateString()}</span>
                </div>
              </div>
              <Link to="/community-admin/profile" className="btn btn-outline">Edit Profile →</Link>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
